import{_ as e,o,c as t,a2 as r}from"./chunks/framework.DnrXFDHb.js";const A=JSON.parse('{"title":"G13: 未來發展與戰略規劃 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3189_景碩/20260423/G13_未來發展與戰略規劃_投資研究員.md","filePath":"審計報告庫/經營審計/3189_景碩/20260423/G13_未來發展與戰略規劃_投資研究員.md"}'),l={name:"審計報告庫/經營審計/3189_景碩/20260423/G13_未來發展與戰略規劃_投資研究員.md"};function i(n,a,d,_,c,s){return o(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="g13-未來發展與戰略規劃-投資研究員-審計報告" tabindex="-1">G13: 未來發展與戰略規劃 - 投資研究員 審計報告 <a class="header-anchor" href="#g13-未來發展與戰略規劃-投資研究員-審計報告" aria-label="Permalink to &quot;G13: 未來發展與戰略規劃 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>公司未來幾年有什麼中長期發展與戰略規劃？有什麼技術布局與合作？多元化轉型是否有譜？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>景碩的戰略規劃高度聚焦：ABF載板為核心成長引擎，BT載板為防禦性現金流業務，2025~2027年資本支出將超350億元全部押注ABF高階產能擴充。具體目標為2026~2027年ABF月產能從約3,800萬顆擴增至5,000萬顆（+32%）。AI ASIC（Google TPU、Broadcom）是最大戰略突破口，而非NVIDIA GPU主流市場。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>A（良）。戰略聚焦ABF載板AI化雖單一但方向清晰，2026年Q2開始ASIC訂單出貨將帶動營收與獲利結構升級。多元化存在但弱勢——BT載板營收佔比從2023年38%降至2025年約28%，非ABF業務（隱形眼鏡子公司晶碩）對集團獲利貢獻&lt;2%。隱形眼鏡屬低關聯度多角化，短期無法成為第二成長曲線。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>ABF產能擴充節奏</strong>：2025年台灣五廠擴產完成、2026年六廠動工（235億元史上最大投資）、2027年全產能開出。目標將高階ABF載板（14L+）佔比從2025年約35%提升至2027年55%。技術路線圖：16L→18L→20L ABF載板，預計2027年開始提供20L樣品。</p><p><strong>ASIC戰略定位</strong>：不同於欣興搶NVIDIA主流GPU載板，景碩押注AI ASIC（特殊應用晶片）的載板需求。Google TPU v6（2026年量產）、Broadcom AI ASIC（2026年出貨）為核心design-win。此策略優點：ASIC毛利率通常高於標準品5-8%、客戶關係較不對稱（共同開發bonding較強）；缺點：單一ASIC客戶退坑風險高。</p><p><strong>多角化限度</strong>：ABF載板佔營收70%+的限制短期無解。BT載板（手機/記憶體）佔營收約28%，2025年因記憶體需求回升小幅成長。非載板業務（子公司晶碩隱形眼鏡）2025年營收約21億元，佔集團營收&lt;5%，未來3年目標也難突破10%。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>景碩的戰略是「AI ABF載板聚焦主義」——靠高資本投入追趕技術世代差。這是一條高風險高回報的路徑：若AI晶片需求維持CAGR 30%以上至2028年，景碩將透過產能擴張和客戶認證雙重鎖定，護城河深化；若AI泡沫破裂，370億元的資本支出將變成沈沒成本黑洞。</p><p>最值得追蹤的戰略風向標：2026年H2 Google TPU v6出貨後的毛利率變化——若從Q2的~23%躍升至Q4的&gt;28%，證明ASIC訂單利潤結構優化的假設成立，股價有上修空間。</p><p>中長期戰略疑慮：景碩目前無任何非載板業務的第二成長曲線規劃，子公司晶碩（隱形眼鏡）營收佔比&lt;5%且成長率僅個位數，不具戰略比重。若單純依賴ABF載板業務，當AI半導體產業進入成熟期（估2029-2030年），公司成長動能將自然減速。屆時景碩需要新的成長引擎，目前檯面上無明確規劃。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>中央社</code>: 2026/03/12 景碩法說會（ABF擴產至2027年、台灣六廠235億投資）</li><li><code>經濟日報</code>: 景碩2025年獲利創新高（全年營收393.5億、EPS 3.51元）</li><li><code>優分析UAnalyze</code>: 景碩ABF/BT載板營收佔比分析（2023-2025）</li><li><code>年報</code>: 景碩年度財務報告（子公司晶碩損益）</li><li><code>工商時報</code>: 法人預估景碩2026年獲利增長動能</li></ul>',17)])])}const p=e(l,[["render",i]]);export{A as __pageData,p as default};
